// Example: IR Receiver
// Decode infrared remote signals on pin 11.

#include <IRremote.h>

int recvPin = 11;
IRrecv irrecv(recvPin);

void setup() {
  Serial.begin(9600);
  irrecv.enableIRIn();
}

void loop() {
  if (irrecv.decode()) {
    Serial.print("IR Code: 0x");
    Serial.println(irrecv.decodedIRData.decodedRawData, HEX);
    irrecv.resume();
  }
  delay(100);
}
